package metrics

import (
	"math"
	"sort"
	"sync"
)

type Histogram struct {
	mu      sync.Mutex
	values  []float64
	buckets []float64
	counts  []int
}

func NewHistogram(buckets []float64) *Histogram {
	sorted := make([]float64, len(buckets))
	copy(sorted, buckets)
	sort.Float64s(sorted)
	return &Histogram{
		buckets: sorted,
		counts:  make([]int, len(sorted)+1),
	}
}

func (h *Histogram) Observe(value float64) {
	h.mu.Lock()
	defer h.mu.Unlock()
	h.values = append(h.values, value)
	idx := sort.SearchFloat64s(h.buckets, value)
	if idx < len(h.buckets) && h.buckets[idx] == value {
		h.counts[idx]++
	} else {
		h.counts[idx]++
	}
}

func (h *Histogram) Percentile(p float64) float64 {
	h.mu.Lock()
	defer h.mu.Unlock()
	if len(h.values) == 0 {
		return 0
	}
	sorted := make([]float64, len(h.values))
	copy(sorted, h.values)
	sort.Float64s(sorted)
	idx := int(math.Ceil(p/100.0*float64(len(sorted)))) - 1
	if idx < 0 {
		idx = 0
	}
	if idx >= len(sorted) {
		idx = len(sorted) - 1
	}
	return sorted[idx]
}

func (h *Histogram) Count() int {
	h.mu.Lock()
	defer h.mu.Unlock()
	return len(h.values)
}

func (h *Histogram) Sum() float64 {
	h.mu.Lock()
	defer h.mu.Unlock()
	var sum float64
	for _, v := range h.values {
		sum += v
	}
	return sum
}

package metrics

import "testing"

func TestHistogramObserveAndCount(t *testing.T) {
	h := NewHistogram([]float64{10, 50, 100, 500})
	h.Observe(5)
	h.Observe(25)
	h.Observe(75)
	if h.Count() != 3 {
		t.Errorf("expected count 3, got %d", h.Count())
	}
}

func TestHistogramPercentile(t *testing.T) {
	h := NewHistogram([]float64{10, 50, 100})
	for i := 1; i <= 100; i++ {
		h.Observe(float64(i))
	}
	p50 := h.Percentile(50)
	if p50 != 50 {
		t.Errorf("expected p50=50, got %f", p50)
	}
	p90 := h.Percentile(90)
	if p90 != 90 {
		t.Errorf("expected p90=90, got %f", p90)
	}
	p99 := h.Percentile(99)
	if p99 != 99 {
		t.Errorf("expected p99=99, got %f", p99)
	}
}

func TestHistogramSum(t *testing.T) {
	h := NewHistogram([]float64{100})
	h.Observe(10)
	h.Observe(20)
	h.Observe(30)
	if h.Sum() != 60 {
		t.Errorf("expected sum 60, got %f", h.Sum())
	}
}
